import usocket as socket
import ujson
from machine import Pin

# Initialize the Pin object to simulate a relay
relay = Pin(2, Pin.OUT)

def handle_connection(connection):
    while True:
        data = connection.recv(1024)
        if not data:
            break
        try:
            command = ujson.loads(data.decode('utf-8'))
            if "action" in command and command["action"] == "turn_on":
                relay.value(1)
            elif "action" in command and command["action"] == "turn_off":
                relay.value(0)
        except ValueError:
            print("Invalid JSON")

def main():
    addr = socket.getaddrinfo("localhost", 80)[0][-1]
    s = socket.socket()
    s.bind(addr)
    s.listen(5)

    while True:
        connection, address = s.accept()
        handle_connection(connection)
        connection.close()

if __name__ == "__main__":
    main()